import React from 'react'
import { useState } from 'react';
import './FoodLog.css';
import { createRoot } from 'react-dom/client';
var numberofMeals = 0;
const socket = new WebSocket('ws://localhost:8080');
socket.binaryType = "arraybuffer";
let mealID = 0;

socket.addEventListener('open', event =>{
    console.log("Socket connection open.")
});

socket.addEventListener('message', event => {
  var searchResults
  console.log('Message from server: ', event.data);
  if(event.data.slice(0,"SEARCH_RESULTS:".length)=="SEARCH_RESULTS:"){
    searchResults = JSON.parse(event.data.slice("SEARCH_RESULTS:".length,event.data.length));
    console.log(searchResults);
  };
  
});

function DeleteBtn(props){
  return (
    <button id={"Delete"+props.key}>Delete meal</button>
  )
}

function Meal(props) {
  return (
    <div className='meal' id={"Meal"+props.key}>
              <h1>{props.name}</h1>
              <DeleteBtn key={props.id}/>
    </div>
  )
}

const FoodLog = () => {
  const [mealname, setMealname] = useState('');
  const [meals, setMeals] = useState([]);

  function addMeal() {
    setMeals([
      ...meals,
      { id:mealID++, name:mealname}
    ]);
  }

  function deleteMeal(ID){
    console.log("MealID is "+ID);
  }
  
  return (
    <div>
      <input value={mealname} onChange={e => setMealname(e.target.value)}></input>
      <button onClick={addMeal}>Add meal</button>
      <ul>
        {meals.map(
          meal => (
            <Meal key={meal.id} name={meal.name} />
          )
        )}
      </ul>
    </div>
  )
}

export default FoodLog
